resource "aws_s3_bucket_lifecycle_configuration" "company_data_archive_prod" {
  bucket = aws_s3_bucket.company_data_archive_prod.id

  rule {
    id     = "transition-to-glacier-instant-retrieval"
    status = "Enabled"

    filter {
      prefix = ""
    }

    transition {
      days          = 90
      storage_class = "GLACIER_IR"
    }
  }

  tags = {
    Name        = "company-data-archive-prod"
    Environment = "production"
    FinOpsAction = "GLACIER_TRANSITION"
    FinOpsReviewed = "true"
  }
}

